module multi_pipe_4bit (
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

wire [3:0] a_ext = {4{1'b0}} + mul_a;
wire [3:0] b_ext = {4{1'b0}} + mul_b;

genvar i;
    for(i = 0; i < 4; i = i+1) begin : gen_mul
        wire [3:0] pp_i = (b_ext[i]) ? (a_ext << i) : 'd0;
    end

reg [7:0] r_sum[0:3];
integer j;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        for(j = 0; j < 4; j = j+1) begin
            r_sum[j] <= 8'd0;
        end
    end else begin
        for(j = 0; j < 4; j = j+1) begin
            r_sum[j] <= r_sum[j] + (i < 4 ? pp_i : 8'd0);
        end
    end
end

reg [7:0] r_prod;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        r_prod <= 8'd0;
    end else begin
        r_prod <= r_sum[0] + r_sum[1] + r_sum[2] + r_sum[3];
    end
end
assign mul_out = r_prod;

endmodule
